func formatComment(s string) template.HTML {
	esc := html.EscapeString(s)

	allowed := []string{"b", "i", "em", "strong", "br"}

	for _, tag := range allowed {
		open := "&lt;" + tag + "&gt;"
		close := "&lt;/" + tag + "&gt;"
		esc = strings.ReplaceAll(esc, open, "<"+tag+">")
		esc = strings.ReplaceAll(esc, close, "</"+tag+">")

		// support <br/> and <br />
		if tag == "br" {
			esc = strings.ReplaceAll(esc, "&lt;br/&gt;", "<br/>")
			esc = strings.ReplaceAll(esc, "&lt;br /&gt;", "<br />")
		}
	}

	return template.HTML(esc)
}

